import UIKit
import Combine

// MARK: - Models
struct Stock: Codable {
    let symbol: String
    let name: String
    let currentPrice: Double
    let change: Double
    let changePercent: Double
}

struct PortfolioItem: Codable {
    let symbol: String
    let quantity: Int
    let averagePrice: Double
    var currentPrice: Double
}

struct Trade: Codable {
    let symbol: String
    let quantity: Int
    let price: Double
    let type: TradeType
    let timestamp: Date
}

enum TradeType: String, Codable {
    case buy
    case sell
}

// MARK: - API Service
class TradingAPIService {
    static let shared = TradingAPIService()
    private let baseURL = "https://api.example.com"
    private let apiKey = "your_api_key_here"
    
    private init() {}
    
    func fetchStocks() -> AnyPublisher<[Stock], Error> {
        guard let url = URL(string: "\(baseURL)/stocks") else {
            return Fail(error: URLError(.badURL)).eraseToAnyPublisher()
        }
        
        return URLSession.shared.dataTaskPublisher(for: url)
            .map(\.data)
            .decode(type: [Stock].self, decoder: JSONDecoder())
            .receive(on: DispatchQueue.main)
            .eraseToAnyPublisher()
    }
    
    func executeTrade(_ trade: Trade) -> AnyPublisher<Bool, Error> {
        guard let url = URL(string: "\(baseURL)/trade") else {
            return Fail(error: URLError(.badURL)).eraseToAnyPublisher()
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue(apiKey, forHTTPHeaderField: "X-API-Key")
        
        do {
            request.httpBody = try JSONEncoder().encode(trade)
        } catch {
            return Fail(error: error).eraseToAnyPublisher()
        }
        
        return URLSession.shared.dataTaskPublisher(for: request)
            .map(\.data)
            .decode(type: TradeResponse.self, decoder: JSONDecoder())
            .map { _ in true }
            .receive(on: DispatchQueue.main)
            .eraseToAnyPublisher()
    }
    
    func fetchPortfolio() -> AnyPublisher<[PortfolioItem], Error> {
        guard let url = URL(string: "\(baseURL)/portfolio") else {
            return Fail(error: URLError(.badURL)).eraseToAnyPublisher()
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue(apiKey, forHTTPHeaderField: "X-API-Key")
        
        return URLSession.shared.dataTaskPublisher(for: request)
            .map(\.data)
            .decode(type: [PortfolioItem].self, decoder: JSONDecoder())
            .receive(on: DispatchQueue.main)
            .eraseToAnyPublisher()
    }
}

struct TradeResponse: Codable {
    let success: Bool
    let transactionId: String
}

// MARK: - View Models
class StockViewModel: ObservableObject {
    @Published var stocks: [Stock] = []
    @Published var isLoading = false
    @Published var errorMessage: String?
    
    private var cancellables = Set<AnyCancellable>()
    
    func loadStocks() {
        isLoading = true
        errorMessage = nil
        
        TradingAPIService.shared.fetchStocks()
            .sink(
                receiveCompletion: { [weak self] completion in
                    self?.isLoading = false
                    if case .failure(let error) = completion {
                        self?.errorMessage = error.localizedDescription
                    }
                },
                receiveValue: { [weak self] stocks in
                    self?.stocks = stocks
                }
            )
            .store(in: &cancellables)
    }
}

class PortfolioViewModel: ObservableObject {
    @Published var portfolio: [PortfolioItem] = []
    @Published var isLoading = false
    @Published var errorMessage: String?
    
    private var cancellables = Set<AnyCancellable>()
    
    func loadPortfolio() {
        isLoading = true
        errorMessage = nil
        
        TradingAPIService.shared.fetchPortfolio()
            .sink(
                receiveCompletion: { [weak self] completion in
                    self?.isLoading = false
                    if case .failure(let error) = completion {
                        self?.errorMessage = error.localizedDescription
                    }
                },
                receiveValue: { [weak self] portfolio in
                    self?.portfolio = portfolio
                }
            )
            .store(in: &cancellables)
    }
}

class TradeViewModel: ObservableObject {
    @Published var isExecuting = false
    @Published var errorMessage: String?
    @Published var successMessage: String?
    
    private var cancellables = Set<AnyCancellable>()
    
    func executeTrade(symbol: String, quantity: Int, type: TradeType) {
        isExecuting = true
        errorMessage = nil
        successMessage = nil
        
        let trade = Trade(
            symbol: symbol,
            quantity: quantity,
            price: 0.0, // Will be fetched from API
            type: type,
            timestamp: Date()
        )
        
        TradingAPIService.shared.executeTrade(trade)
            .sink(
                receiveCompletion: { [weak self] completion in
                    self?.isExecuting = false
                    if case .failure(let error) = completion {
                        self?.errorMessage = error.localizedDescription
                    }
                },
                receiveValue: { [weak self] success in
                    if success {
                        self?.successMessage = "Trade executed successfully!"
                    }
                }
            )
            .store(in: &cancellables)
    }
}

// MARK: - Views
struct StockListView: View {
    @StateObject private var viewModel = StockViewModel()
    
    var body: some View {
        NavigationView {
            VStack {
                if viewModel.isLoading {
                    ProgressView()
                } else if let error = viewModel.errorMessage {
                    Text(error)
                        .foregroundColor(.red)
                } else {
                    List(viewModel.stocks) { stock in
                        StockRowView(stock: stock)
                    }
                }
            }
            .navigationTitle("Stocks")
            .onAppear {
                viewModel.loadStocks()
            }
        }
    }
}

struct StockRowView: View {
    let stock: Stock
    
    var body: some View {
        HStack {
            VStack(alignment: .leading) {
                Text(stock.symbol)
                    .font(.headline)
                Text(stock.name)
                    .font(.caption)
                    .foregroundColor(.secondary)
            }
            Spacer()
            VStack(alignment: .trailing) {
                Text(String(format: "$%.2f", stock.currentPrice))
                    .font(.headline)
                Text(String(format: "%.2f%%", stock.changePercent))
                    .foregroundColor(stock.change >= 0 ? .green : .red)
            }
        }
        .padding()
    }
}

