struct TradeView: View {
    @StateObject private var viewModel = TradeViewModel()
    @State private var symbol = ""
    @State private var quantity = 1
    @State private var tradeType: TradeType = .buy
    
    var body: some View {
        NavigationView {
            Form {
                Section(header: Text("Trade Details")) {
                    Picker("Type", selection: $tradeType) {
                        Text("Buy").tag(TradeType.buy)
                        Text("Sell").tag(TradeType.sell)
                    }
                    
                    TextField("Symbol", text: $symbol)
                    
                    Stepper("Quantity: \(quantity)", value: $quantity, in: 1...1000)
                }
                
                Section {
                    Button("Execute Trade") {
                        viewModel.executeTrade(symbol: symbol, quantity: quantity, type: tradeType)
                    }
                    .disabled(symbol.isEmpty || viewModel.isExecuting)
                }
                
                if viewModel.isExecuting {
                    HStack {
                        ProgressView()
                        Text("Executing...")
                    }
                }
                
                if let error = viewModel.errorMessage {
                    Text(error)
                        .foregroundColor(.red)
                }
                
                if let success = viewModel.successMessage {
                    Text(success)
                        .foregroundColor(.green)
                }
            }
            .navigationTitle("Trade")
        }
    }
}

